// Student.java — the class (blueprint)
class Student {
    String name;
    int age;
    double gpa;

    // Constructor
    Student(String name, int age, double gpa) {
        this.name = name;
        this.age = age;
        this.gpa = gpa;
    }

    // Method
    void displayInfo() {
        System.out.println("Name: " + name);
        System.out.println("Age: " + age);
        System.out.println("GPA: " + gpa);
        System.out.println("---");
    }
}

// Main class
public class Main {
    public static void main(String[] args) {
        // Creating objects (instances)
        Student alice = new Student("Alice", 20, 3.8);
        Student bob = new Student("Bob", 22, 3.2);

        // Accessing fields
        System.out.println("Alice's name: " + alice.name);

        // Calling methods
        alice.displayInfo();
        bob.displayInfo();

        // this keyword
        // Inside the constructor, this refers to the current object
        // this.name = name; assigns the parameter to the field
    }
}

